mapper.insert:
insert into `community_post` (
    creator_id, author_name, forum_name, title, summary, content,
    reply_count, like_count, favorite_count, status, created_at, updated_at
) values (
    #{creatorId}, #{authorName}, #{forumName}, #{title}, #{summary}, #{content},
    #{replyCount}, #{likeCount}, #{favoriteCount}, #{status}, #{createdAt}, #{updatedAt}
)

mapper.select:
select 
from `community_post`


        status = #{status}


        and forum_name = #{forumName}


        and creator_id = #{creatorId}


        and (
            title like concat('%', #{keyword}, '%')
            or summary like concat('%', #{keyword}, '%')
            or content like concat('%', #{keyword}, '%')
        )


order by created_at desc, id desc
